def create_task(title, description):
    if title is None or (isinstance(title, str) and (not title.strip())):
        return _cm_failure('create_task', 'title is required', 'missing_title', None)
    if description is None or (isinstance(description, str) and (not description.strip())):
        return _cm_failure('create_task', 'description is required', 'missing_description', None)
    tasks = load_tasks()
    task_id = max((int(i) for i in tasks), default=-1) + 1
    new_task = {'id': str(task_id), 'title': title, 'description': description}
    tasks[str(task_id)] = new_task
    save_tasks(tasks)
    return _cm_success('create_task', f'Task {title} created successfully.', new_task)

def get_all_tasks():
    tasks = load_tasks()
    return _cm_success('get_all_tasks', 'All tasks fetched successfully.', list(tasks.values()))

def update_task(id, new_data):
    tasks = load_tasks()
    if id not in tasks:
        return _cm_failure('update_task', f'Task with ID {id} does not exist.', f'Task with ID {id} does not exist.', None)
    tasks[id].update(new_data)
    save_tasks(tasks)
    return _cm_success('update_task', f'Task {id} updated successfully.', tasks[id])

def delete_task(id):
    tasks = load_tasks()
    if id not in tasks:
        return _cm_failure('delete_task', f'Task with ID {id} does not exist.', f'Task with ID {id} does not exist.', None)
    del tasks[id]
    save_tasks(tasks)
    return _cm_success('delete_task', f'Task {id} deleted successfully.', None)

def load_tasks():
    try:
        with open(DATA_DIR / 'tasks.json', 'r') as file:
            tasks = json.load(file)
    except FileNotFoundError:
        tasks = {}
    return tasks

def save_tasks(tasks):
    if tasks is None or (isinstance(tasks, str) and (not tasks.strip())):
        return _cm_failure('save_tasks', 'tasks is required', 'missing_tasks', None)
    DATA_DIR.mkdir(parents=True, exist_ok=True)
    with open(DATA_DIR / 'tasks.json', 'w') as file:
        json.dump(tasks, file)

